export function getAllCards(): Card[] {
  return allCardData;
}

export function getUnlockedCards(startDate: string): Card[] {
  const start = new Date(startDate);
  const now = new Date();
  const diffDays = Math.floor((now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  
  return allCardData.filter(card => card.day <= diffDays + 1);
}

export function getVocabCards(): Card[] {
  return allCardData.filter(card => card.type === 'vocab');
}

export function getPhraseCards(): Card[] {
  return allCardData.filter(card => card.type === 'phrase');
}

export function getCardById(id: string): Card | undefined {
  return allCardData.find(c => c.id === id);
}
